import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import { 
  getAllUsers, 
  getAllProjects, 
  getProjectProposals 
} from "../../api/api";

const Reports = () => {

  const [data, setData] = useState({
    users: 0,
    projects: 0,
    proposals: 0
  });

  useEffect(() => {
    fetchReport();
  }, []);

  const fetchReport = async () => {
    try {
      const usersRes = await getAllUsers();
      const projectsRes = await getAllProjects();
      const proposalsRes = await getProjectProposals();

      setData({
        users: usersRes.data.length,
        projects: projectsRes.data.length,
        proposals: proposalsRes.data.length
      });
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div className="flex">

      {/* SIDEBAR */}
      <Sidebar />

      {/* MAIN CONTENT */}
      <div className="flex-1 p-8 bg-gray-100 min-h-screen">

        <h1 className="text-3xl font-bold mb-6">
          Reports & Analytics
        </h1>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          <div className="bg-white shadow-lg rounded-xl p-6">
            <h3 className="text-gray-500 mb-2">Total Users</h3>
            <p className="text-3xl font-bold text-blue-600">
              {data.users}
            </p>
          </div>

          <div className="bg-white shadow-lg rounded-xl p-6">
            <h3 className="text-gray-500 mb-2">Total Projects</h3>
            <p className="text-3xl font-bold text-green-600">
              {data.projects}
            </p>
          </div>

          <div className="bg-white shadow-lg rounded-xl p-6">
            <h3 className="text-gray-500 mb-2">Total Proposals</h3>
            <p className="text-3xl font-bold text-purple-600">
              {data.proposals}
            </p>
          </div>

        </div>

      </div>
    </div>
  );
};

export default Reports;
